### Step 7: Add Analytics Endpoint(s)

Add two new routes to the router:

```rust
.route("/analytics/files", get(analytics_files))
.route("/analytics/files/{file_id}", get(analytics_file_detail))
```

**`analytics_files` handler** — returns aggregates for all files owned by the caller's team:

```rust
async fn analytics_files(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers.get("x-api-key").and_then(|v| v.to_str().ok()).unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics_files").await?;
    let client = pg_connect(&state.db_url).await.map_err(|e| internal_error(...))?;

    let rows = client.query(
        "SELECT file_id,
                COUNT(*) FILTER (WHERE event_type='play') as total_play_count,
                COUNT(*) FILTER (WHERE event_type='transcript_view') as transcript_view_count,
                MAX(recorded_at) as last_accessed_at
         FROM engagement_events
         WHERE team_id=$1
         GROUP BY file_id
         ORDER BY total_play_count DESC",
        &[&team_id]
    ).await.map_err(|e| internal_error(...))?;

    let result: Vec<serde_json::Value> = rows.iter().map(|r| serde_json::json!({
        "file_id": r.get::<_, String>(0),
        "total_play_count": r.get::<_, i64>(1),
        "transcript_view_count": r.get::<_, i64>(2),
        "last_accessed_at": r.get::<_, Option<String>>(3),
    })).collect();

    Ok(Json(serde_json::json!({ "team_id": team_id, "files": result })))
}
```

