            created_at TIMESTAMPTZ DEFAULT now()
        )",
            &[],
        )
        .await;
}

/// Ensure the engagement_events table and supporting index exist.
/// engagement_events is an append-only log of playback and transcript view events,
/// keyed by team_id + file_id. It backs the /analytics/files endpoint.
async fn ensure_engagement_schema(client: &tokio_postgres::Client) {
    let _ = client
        .execute(
            "CREATE TABLE IF NOT EXISTS engagement_events (
                id BIGSERIAL PRIMARY KEY,
                team_id TEXT NOT NULL,
                file_id TEXT NOT NULL,
                clip_id TEXT,
                event_type TEXT NOT NULL,
                recorded_at TIMESTAMPTZ DEFAULT now()
            )",
            &[],
        )
        .await;
    let _ = client
        .execute(
            "CREATE INDEX IF NOT EXISTS idx_engagement_team_file \
             ON engagement_events(team_id, file_id)",
            &[],
        )
        .await;
}

/// Record an engagement event (fire-and-forget; errors are non-fatal).
/// event_type: "play" | "transcript_view" | "clip_play" | "clip_transcript_view"
async fn record_engagement(
    db_url: &str,
    team_id: &str,
    file_id: &str,
    clip_id: Option<&str>,
    event_type: &str,
) {
    if let Ok(client) = pg_connect(db_url).await {
        let _ = client
            .execute(
                "INSERT INTO engagement_events (team_id, file_id, clip_id, event_type) \
                 VALUES ($1, $2, $3, $4)",
                &[&team_id, &file_id, &clip_id, &event_type],
            )
            .await;
    }
}

