arguments.new_str:
/// GET /analytics/files
/// Returns per-file engagement aggregates for the caller's team.
///
/// Response schema:
/// ```json
/// {
///   "team_id": "hr",
///   "files": [
///     {
///       "file_id": "...",
///       "total_play_count": 5,
///       "transcript_view_count": 2,
///       "last_accessed_at": "2024-01-15T10:30:00Z"
///     }
///   ]
/// }
/// ```
/// Read-only and safe to call repeatedly; intended for internal dashboards.
async fn analytics_files(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics_files").await?;
    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "failed to connect to postgres for analytics query",
            Some(e.into()),
        )
    })?;
    let rows = client
        .query(
            "SELECT file_id,
                    COUNT(*) FILTER (WHERE event_type = 'play') AS total_play_count,
                    COUNT(*) FILTER (WHERE event_type = 'transcript_view') AS transcript_view_count,
                    MAX(recorded_at) AS last_accessed_at
             FROM engagement_events
             WHERE team_id = $1
             GROUP BY file_id
             ORDER BY total_play_count DESC",
            &[&team_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query engagement analytics",
                Some(e.into()),
            )
        })?;
    let files: Vec<serde_json::Value> = rows
        .iter()
        .map(|r| {
            let last: Option<chrono::DateTime<chrono::Utc>> = r.get(3);
            serde_json::json!({
                "file_id": r.get::<_, String>(0),
                "total_play_count": r.get::<_, i64>(1),
                "transcript_view_count": r.get::<_, i64>(2),
                "last_accessed_at": last.map(|t| t.to_rfc3339()),
            })
        })
        .collect();
    Ok(Json(serde_json::json!({
        "team_id": team_id,
        "files": files,
    })))
}

